export class SetReputationScoreCall extends ethereum.Call {
  get inputs(): SetReputationScoreCall__Inputs {
    return new SetReputationScoreCall__Inputs(this);
  }

  get outputs(): SetReputationScoreCall__Outputs {
    return new SetReputationScoreCall__Outputs(this);
  }
}

export class SetReputationScoreCall__Inputs {
  _call: SetReputationScoreCall;

  constructor(call: SetReputationScoreCall) {
    this._call = call;
  }

  get candidate(): Address {
    return this._call.inputValues[0].value.toAddress();
  }

  get sum(): BigInt {
    return this._call.inputValues[1].value.toBigInt();
  }

  get count(): BigInt {
    return this._call.inputValues[2].value.toBigInt();
  }
}

export class SetReputationScoreCall__Outputs {
  _call: SetReputationScoreCall;

  constructor(call: SetReputationScoreCall) {
    this._call = call;
  }
}

